import edu.ucr.cs.bdlab.davinci.VectorLayerBuilder

// Test zigzagDecode with a known encoded value.
// Zigzag encoding for a positive integer `x` is `x * 2`.
// Zigzag encoding for a negative integer `x` is `abs(x) * 2 - 1`.
// Let's test the decoding of a positive value (12345) and a negative value (-6789).
// Encoded value for 12345 is 24690.
// Encoded value for -6789 is (6789 * 2) - 1 = 13578 - 1 = 13577.

val encodedPositive: Int = 24690
val decodedPositive: Int = VectorLayerBuilder.zigzagDecode(encodedPositive)
require(decodedPositive == 12345, s"Expected zigzagDecode($encodedPositive) to be 12345 but got $decodedPositive")

val encodedNegative: Int = 13577
val decodedNegative: Int = VectorLayerBuilder.zigzagDecode(encodedNegative)
require(decodedNegative == -6789, s"Expected zigzagDecode($encodedNegative) to be -6789 but got $decodedNegative")

// The witness will be the sum of the two decoded values.
val witness = decodedPositive + decodedNegative
require(witness == (12345 - 6789), "Witness value calculation is incorrect")

println("__CHECK__ zigzagDecode " + witness)

